const MAX_LOG_ENTRIES = 500;
const MAX_LOG_SIZE_BYTES = 2 * 1024 * 1024; // 2MB max
const LOG_STORAGE_KEY = '@DebugLogger:logs';
const SESSION_STORAGE_KEY = '@DebugLogger:session';

class LogStorage {
  constructor() {
    this.logs = [];
    this.currentSize = 0;
    this.flushTimer = null;
    this.flushInterval = 30000; // 30 seconds
  }

  add(entry) {
    const serialized = JSON.stringify(entry);
    const entrySize = serialized.length * 2; // rough byte estimate

    // Evict old entries if we exceed limits
    while (
      (this.logs.length >= MAX_LOG_ENTRIES || this.currentSize + entrySize > MAX_LOG_SIZE_BYTES)
      && this.logs.length > 0
    ) {
      const removed = this.logs.shift();
      this.currentSize -= (JSON.stringify(removed).length * 2);
    }

    this.logs.push(entry);
    this.currentSize += entrySize;

    this.scheduleFlush();
  }

  scheduleFlush() {
    if (this.flushTimer) return;
    this.flushTimer = setTimeout(() => {
      this.flush();
      this.flushTimer = null;
    }, this.flushInterval);
  }

  async flush() {
    try {
      const data = JSON.stringify(this.logs.slice(-MAX_LOG_ENTRIES));
      await AsyncStorage.setItem(LOG_STORAGE_KEY, data);
    } catch (error) {
      // Silent fail - don't log to avoid recursion
    }
  }

  async loadPersisted() {
    try {
      const data = await AsyncStorage.getItem(LOG_STORAGE_KEY);
      if (data) {
        this.logs = JSON.parse(data);
        this.currentSize = data.length * 2;
      }
    } catch {
      this.logs = [];
    }
  }

  getAll() {
    return [...this.logs];
  }

  getLast(count = 50) {
    return this.logs.slice(-count);
  }

  clear() {
    this.logs = [];
    this.currentSize = 0;
    AsyncStorage.removeItem(LOG_STORAGE_KEY).catch(() => {});
  }
}

