// REACT HOOKS & COMPONENTS
// ============================================================

import React, { useEffect, useRef, useCallback } from 'react';
import { AppState, TouchableOpacity, Text, View, ScrollView, StyleSheet } from 'react-native';

// Hook to track component renders
export function useRenderLogger(componentName) {
  const renderCount = useRef(0);
  const renderStart = useRef(Date.now());

  useEffect(() => {
    const renderTime = Date.now() - renderStart.current;
    renderCount.current += 1;

    logger.trackRenderTime(componentName, renderTime);

    return () => {
      logger.debug('Component', `${componentName} unmounted`, {
        totalRenders: renderCount.current,
      });
    };
  });

  useEffect(() => {
    renderStart.current = Date.now();
  });

  return renderCount.current;
}

// Hook to track app state changes
export function useAppStateLogger() {
  useEffect(() => {
    const subscription = AppState.addEventListener('change', (nextAppState) => {
      logger.trackAppState(nextAppState);
    });

    return () => {
      subscription?.remove();
    };
  }, []);
}

// Hook for performance timing
export function usePerformanceTimer(label) {
  const startRef = useRef(null);

  const start = useCallback(() => {
    startRef.current = Date.now();
    logger.startTimer(label);
  }, [label]);

  const stop = useCallback(() => {
    return logger.endTimer(label);
  }, [label]);

  return { start, stop };
}

// HOC to wrap navigation for tracking
export function withNavigationLogger(WrappedComponent, screenName) {
  return function NavigationLoggedComponent(props) {
    useEffect(() => {
      logger.trackNavigation(screenName, props.route?.params);
    }, []);

    useRenderLogger(screenName);

    return <WrappedComponent {...props} />;
  };
}

// Tracked button component
export function TrackedButton({ onPress, trackingId, children, style, ...props }) {
  const handlePress = useCallback((...args) => {
    logger.trackButtonPress(trackingId);
    if (onPress) onPress(...args);
  }, [onPress, trackingId]);

  return (
    <TouchableOpacity onPress={handlePress} style={style} {...props}>
      {typeof children === 'string' ? <Text>{children}</Text> : children}
    </TouchableOpacity>
  );
}

// Error Boundary with logging
export class LoggedErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    logger.error('ErrorBoundary', 'Component Error Caught', {
      message: error.message,
      name: error.name,
      stack: error.stack ? error.stack.split('\n').slice(0, 10).join('\n') : null,
      componentStack: errorInfo?.componentStack ? errorInfo.componentStack.split('\n').slice(0, 10).join('\n') : null,
      boundaryName: this.props.name || 'Unknown',
    });
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }
      return (
        <View style={styles.errorContainer}>
          <Text style={styles.errorText}>Something went wrong</Text>
          <TrackedButton
            trackingId="error_boundary_retry"
            onPress={() => this.setState({ hasError: false, error: null })}
            style={styles.retryButton}
          >
            <Text style={styles.retryText}>Retry</Text>
          </TrackedButton>
        </View>
      );
    }
    return this.props.children;
  }
}

// ============================================================
// DEBUG OVERLAY (Dev/Staging only)
// ============================================================

export function DebugOverlay({ visible = false }) {
  const [logs, setLogs] = React.useState([]);
  const [expanded, setExpanded] = React.useState(false);

  // Only render in non-production
  if (CURRENT_ENV === ENV.PRODUCTION || !visible) return null;

  const refreshLogs = () => {
    setLogs(logger.storage.getLast(20));
  };

  useEffect(() => {
    refreshLogs();
    const interval = setInterval(refreshLogs, 5000);
    return () => clearInterval(interval);
  }, []);

  if (!expanded) {
    return (
      <TouchableOpacity
        style={styles.debugBubble}
        onPress={() => setExpanded(true)}
      >
        <Text style={styles.debugBubbleText}>🐛</Text>
      </TouchableOpacity>
    );
  }

  return (
    <View style={styles.debugOverlay}>
      <View style={styles.debugHeader}>
        <Text style={styles.debugTitle}>Debug Logs</Text>
        <View style={styles.debugActions}>
          <TouchableOpacity onPress={refreshLogs}>
            <Text style={styles.debugAction}>Refresh</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => logger.clearLogs()}>
            <Text style={styles.debugAction}>Clear</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={async () => {
            const report = await logger.generateDebugReport();
            console.log('DEBUG REPORT:', JSON.stringify(report, null, 2));
          }}>
            <Text style={styles.debugAction}>Report</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => setExpanded(false)}>
            <Text style={styles.debugAction}>✕</Text>
          </TouchableOpacity>
        </View>
      </View>
      <ScrollView style={styles.debugLogList}>
        {logs.map((log, index) => (
          <View key={log.id || index} style={[
            styles.debugLogEntry,
            log.level === 'ERROR' && styles.debugLogError,
            log.level === 'WARN' && styles.debugLogWarn,
          ]}>
            <Text style={styles.debugLogTime}>
              {new Date(log.timestamp).toLocaleTimeString()}
            </Text>
            <Text style={styles.debugLogLevel}>[{log.level}]</Text>
            <Text style={styles.debugLogCategory}>[{log.category}]</Text>
            <Text style={styles.debugLogMessage} numberOfLines={2}>
              {log.message}
            </Text>
          </View>
        ))}
      </ScrollView>
    </View>
  );
}

