// ============================================================
// ZUSTAND MIDDLEWARE (if using Zustand)
// ============================================================

export function zustandDebugMiddleware(storeName) {
  return (config) => (set, get, api) => {
    const trackedSet = (...args) => {
      const prevState = get();
      set(...args);
      const nextState = get();
      logger.trackStateChange(storeName, args[2] || 'SET', prevState, nextState);
    };
    return config(trackedSet, get, api);
  };
}

// ============================================================
// AXIOS INTERCEPTOR (if using Axios)
// ============================================================

export function installAxiosInterceptor(axiosInstance) {
  axiosInstance.interceptors.request.use(
    (config) => {
      config._debugStartTime = Date.now();
      config._debugRequestId = `axios_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;

      logger.info('Network:Axios:Request', `${config.method?.toUpperCase()} ${sanitizeUrl(config.url)}`, {
        requestId: config._debugRequestId,
        url: sanitizeUrl(config.url),
        method: config.method?.toUpperCase(),
        headers: sanitizeHeaders(config.headers || {}),
        params: sanitizeObject(config.params),
        data: sanitizeBody(config.data),
      });

      return config;
    },
    (error) => {
      logger.error('Network:Axios:RequestError', 'Request interceptor error', {
        message: error.message,
      });
      return Promise.reject(error);
    }
  );

  axiosInstance.interceptors.response.use(
    (response) => {
      const duration = Date.now() - (response.config._debugStartTime || Date.now());

      logger.info('Network:Axios:Response', `${response.status} ${response.config.method?.toUpperCase()} ${sanitizeUrl(response.config.url)} (${duration}ms)`, {
        requestId: response.config._debugRequestId,
        status: response.status,
        url: sanitizeUrl(response.config.url),
        duration: `${duration}ms`,
        responseData: sanitizeBody(response.data),
        responseHeaders: sanitizeHeaders(response.headers || {}),
      });

      return response;
    },
    (error) => {
      const config = error.config || {};
      const duration = Date.now() - (config._debugStartTime || Date.now());

      logger.error('Network:Axios:ResponseError', `FAILED ${config.method?.toUpperCase()} ${sanitizeUrl(config.url)} (${duration}ms)`, {
        requestId: config._debugRequestId,
        url: sanitizeUrl(config.url),
        status: error.response?.status,
        statusText: error.response?.statusText,
        message: error.message,
        responseData: error.response ? sanitizeBody(error.response.data) : null,
        duration: `${duration}ms`,
      });

      return Promise.reject(error);
    }
  );
}

// ============================================================
// EXPORTS
// ============================================================

export {
  sanitizeObject,
  sanitizeHeaders,
  sanitizeUrl,
  sanitizeBody,
  maskValue,
  LOG_LEVEL,
  ENV,
  CURRENT_ENV,
};

export default logger;